import{_ as l,o as i,c as e,ag as t}from"./chunks/framework.CAXxHpAX.js";const m=JSON.parse('{"title":"Alma 客户端配置指南","description":"","frontmatter":{},"headers":[],"relativePath":"apps/alma.md","filePath":"apps/alma.md"}'),r={name:"apps/alma.md"};function o(d,a,h,n,u,p){return i(),e("div",null,[...a[0]||(a[0]=[t('<h1 id="alma-客户端配置指南" tabindex="-1">Alma 客户端配置指南 <a class="header-anchor" href="#alma-客户端配置指南" aria-label="Permalink to &quot;Alma 客户端配置指南&quot;">​</a></h1><p>功能强大的 AI 编程客户端工具</p><p>📋 简介</p><p>Alma 是一款功能强大且界面精美的 AI 客户端工具，集成了代码编写、终端操作、Git 管理、浏览器等多种功能，为开发者提供完整的 AI 辅助编程体验。</p><h2 id="相关链接" tabindex="-1">相关链接 <a class="header-anchor" href="#相关链接" aria-label="Permalink to &quot;相关链接&quot;">​</a></h2><table tabindex="0"><thead><tr><th>资源</th><th>地址</th></tr></thead><tbody><tr><td>Alma 官网</td><td><a href="https://alma.now/" target="_blank" rel="noreferrer">https://alma.now/</a></td></tr></tbody></table><h2 id="功能特点" tabindex="-1">功能特点 <a class="header-anchor" href="#功能特点" aria-label="Permalink to &quot;功能特点&quot;">​</a></h2><p>Alma 提供以下强大功能：</p><ul><li>✅ 代码编写：智能代码生成和补全</li><li>✅ 终端操作：集成终端，直接执行命令</li><li>✅ Git 管理：可视化 Git 操作</li><li>✅ 浏览器集成：内置浏览器支持</li><li>✅ 多模型支持：支持 Claude、Gemini 等多种模型</li><li>✅ 自定义供应商：可接入自定义 API 提供商</li></ul><h2 id="安装与配置" tabindex="-1">安装与配置 <a class="header-anchor" href="#安装与配置" aria-label="Permalink to &quot;安装与配置&quot;">​</a></h2><h3 id="第一步-安装-alma" tabindex="-1">第一步：安装 Alma <a class="header-anchor" href="#第一步-安装-alma" aria-label="Permalink to &quot;第一步：安装 Alma&quot;">​</a></h3><p>访问 Alma 官网下载并安装适合你操作系统的版本。</p><h3 id="第二步-设置中文界面" tabindex="-1">第二步：设置中文界面 <a class="header-anchor" href="#第二步-设置中文界面" aria-label="Permalink to &quot;第二步：设置中文界面&quot;">​</a></h3><p>为了更好的使用体验，建议将界面设置为中文：</p><ol><li>打开 Alma 应用</li><li>进入 设置 → 通用 → 语言</li><li>选择「中文」</li></ol><h3 id="第三步-添加-ikuncode-自定义供应商" tabindex="-1">第三步：添加 IkunCode 自定义供应商 <a class="header-anchor" href="#第三步-添加-ikuncode-自定义供应商" aria-label="Permalink to &quot;第三步：添加 IkunCode 自定义供应商&quot;">​</a></h3><ol><li>进入供应商设置</li></ol><p>点击 选择供应商 → Add Custom Provider（添加自定义提供商）</p><ol start="2"><li>配置 IkunCode 供应商</li></ol><p>填写以下信息：</p><ul><li>Provider Name：IkunCode（或自定义名称）</li><li>Base URL：<code>https://api.ikuncode.cc/v1</code></li><li>API Key：粘贴你从 IkunCode 控制台创建的 API Key</li></ul><p>💡 提示</p><ul><li>Claude 模型：确保使用 只允许逆向分组的 API Key</li><li>Gemini 模型：确保使用 gemini 分组的 API Key</li><li>IkunCode 的 Codex 暂不支持第三方客户端调用</li></ul><ol start="3"><li>获取可用模型</li></ol><p>添加完成后，在 IkunCode 供应商界面点击 Fetch（获取）按钮，系统会自动获取所有可用模型。</p><p>选择你需要的模型即可开始使用。</p><h3 id="第四步-配置多个分组-可选" tabindex="-1">第四步：配置多个分组（可选） <a class="header-anchor" href="#第四步-配置多个分组-可选" aria-label="Permalink to &quot;第四步：配置多个分组（可选）&quot;">​</a></h3><p>IkunCode 支持通过不同的 API Key（不同分组）访问不同的模型集合。</p><p>在供应商界面，你可以：</p><ol><li>填写不同分组的 API Key</li><li>获取对应分组的模型列表</li><li>根据需求切换使用</li></ol><p>💡 提示</p><p>如需使用 Gemini 3 的画图功能，需要选择 default 渠道的 API Key。</p><h2 id="新建聊天与使用" tabindex="-1">新建聊天与使用 <a class="header-anchor" href="#新建聊天与使用" aria-label="Permalink to &quot;新建聊天与使用&quot;">​</a></h2><h3 id="重要设置提醒" tabindex="-1">重要设置提醒 <a class="header-anchor" href="#重要设置提醒" aria-label="Permalink to &quot;重要设置提醒&quot;">​</a></h3><p>在新建聊天时，上下文范围 设置非常重要：</p><p>⚠️ 强烈建议</p><p>选择「全选」而非「自动」！</p><p>经测试，选择「自动」时模型会产生严重的幻觉问题，可能导致：</p><ul><li>引用不存在的文件</li><li>生成错误的代码逻辑</li><li>误解项目结构</li></ul><p>选择「全选」可以确保模型获得完整的上下文信息，提供更准确的响应。</p><h3 id="使用技巧" tabindex="-1">使用技巧 <a class="header-anchor" href="#使用技巧" aria-label="Permalink to &quot;使用技巧&quot;">​</a></h3><ol><li>代码编写</li></ol><ul><li>描述你的需求，Alma 会生成对应代码</li><li>支持多文件操作和项目级别的修改</li><li>可以实时预览和修改生成的代码</li></ul><ol start="2"><li>终端操作</li></ol><ul><li>集成终端直接执行命令</li><li>支持查看命令执行结果</li><li>可以与 AI 互动调试问题</li></ul><ol start="3"><li>Git 管理</li></ol><ul><li>可视化查看 Git 状态</li><li>AI 辅助编写提交信息</li><li>支持分支管理和合并操作</li></ul><ol start="4"><li>文件浏览</li></ol><ul><li>浏览项目文件结构</li><li>快速定位和编辑文件</li><li>支持文件搜索和过滤</li></ul><h2 id="最佳实践" tabindex="-1">最佳实践 <a class="header-anchor" href="#最佳实践" aria-label="Permalink to &quot;最佳实践&quot;">​</a></h2><h3 id="_1-选择合适的模型" tabindex="-1">1. 选择合适的模型 <a class="header-anchor" href="#_1-选择合适的模型" aria-label="Permalink to &quot;1. 选择合适的模型&quot;">​</a></h3><ul><li>Claude Sonnet：适合日常编码任务，速度快</li><li>Claude Opus：适合复杂的架构设计和难题</li><li>Gemini：适合需要多模态能力的任务（如图片理解）</li></ul><h3 id="_2-合理使用上下文" tabindex="-1">2. 合理使用上下文 <a class="header-anchor" href="#_2-合理使用上下文" aria-label="Permalink to &quot;2. 合理使用上下文&quot;">​</a></h3><ul><li>对于小型项目，可以「全选」所有文件</li><li>对于大型项目，选择相关的模块和文件</li><li>定期清理不相关的上下文，避免 token 浪费</li></ul><h3 id="_3-充分利用-alma-的集成功能" tabindex="-1">3. 充分利用 Alma 的集成功能 <a class="header-anchor" href="#_3-充分利用-alma-的集成功能" aria-label="Permalink to &quot;3. 充分利用 Alma 的集成功能&quot;">​</a></h3><ul><li>使用终端功能验证 AI 生成的代码</li><li>利用 Git 集成管理代码版本</li><li>通过浏览器功能查看文档和参考资料</li></ul><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><h3 id="如何切换不同的-api-提供商" tabindex="-1">如何切换不同的 API 提供商？ <a class="header-anchor" href="#如何切换不同的-api-提供商" aria-label="Permalink to &quot;如何切换不同的 API 提供商？&quot;">​</a></h3><p>在聊天界面顶部的模型选择器中，可以随时切换不同的提供商和模型。</p><h3 id="为什么有些模型无法使用" tabindex="-1">为什么有些模型无法使用？ <a class="header-anchor" href="#为什么有些模型无法使用" aria-label="Permalink to &quot;为什么有些模型无法使用？&quot;">​</a></h3><ul><li>检查对应的 API Key 是否有权限访问该模型</li><li>确认账户余额是否充足</li><li>查看 IkunCode 控制台的令牌组设置（Claude 用 只允许逆向分组，Gemini 用 gemini 分组）</li></ul><h3 id="alma-和-claude-code-有什么区别" tabindex="-1">Alma 和 Claude Code 有什么区别？ <a class="header-anchor" href="#alma-和-claude-code-有什么区别" aria-label="Permalink to &quot;Alma 和 Claude Code 有什么区别？&quot;">​</a></h3><table tabindex="0"><thead><tr><th>特性</th><th>Alma</th><th>Claude Code</th></tr></thead><tbody><tr><td>界面</td><td>图形化界面</td><td>命令行界面</td></tr><tr><td>适用场景</td><td>全功能开发环境</td><td>终端快速操作</td></tr><tr><td>集成功能</td><td>终端、Git、浏览器等</td><td>纯命令行工具</td></tr><tr><td>学习曲线</td><td>较低</td><td>较高</td></tr></tbody></table><p>可以根据具体需求选择使用。</p><h3 id="更多问题" tabindex="-1">更多问题 <a class="header-anchor" href="#更多问题" aria-label="Permalink to &quot;更多问题&quot;">​</a></h3><p>请查看 FAQ 或联系售后支持。</p><h2 id="完成" tabindex="-1">完成 <a class="header-anchor" href="#完成" aria-label="Permalink to &quot;完成&quot;">​</a></h2><p>🎉 配置完成！现在你可以愉快地使用 Alma 进行 AI 辅助编程了！</p><p>记住以下要点：</p><ul><li>✅ 选择「全选」上下文范围</li><li>✅ 根据任务选择合适的模型</li><li>✅ 充分利用 Alma 的集成功能</li><li>✅ 定期检查 API 余额</li></ul>',70)])])}const c=l(r,[["render",o]]);export{m as __pageData,c as default};
